1	'use strict';
2	// 항목별 사용량 telemetry + 결정론적 노후화(stale/archived) 계산.
3	//
4	// 신호는 두 종류다(plan2.md 1절):
5	//  - A) 편집/변경 — backbone, 항상 가능. canonical git 이력(churn_count·last_changed),
6	//       git 저장소가 아니면 파일 mtime 폴백.
7	//  - B) 실제 호출 — best-effort. invocation_count·last_invoked. (이 모듈은 B를 "건드리지" 않는다.
8	//       기본 0/null로만 두고, 별도 작업이 채울 수 있게 병합 시 기존 B 값을 보존한다.)
9	//
10	// 활동 = max(last_changed, last_invoked). 무활동 기간으로 상태를 전이한다(LLM 없이):
11	//   active → stale(기본 30일) → archived(기본 90일). pinned=true면 전이에서 제외.
12	//
13	// 사이드카: canonicalRoot()/.telemetry.json (항목 id → 메타).
14	// 설정:    canonicalRoot()/.telemetry-config.json {staleDays, archiveDays} (없으면 코드 상수).
15	
16	const fs = require('fs');
17	const path = require('path');
18	const { execFileSync } = require('child_process');
19	
20	const paths = require('./paths');
21	const canonical = require('./canonical');
22	
23	// 기본 노후화 임계값(일). .telemetry-config.json 으로 덮어쓸 수 있다.
24	const DEFAULT_THRESHOLDS = { staleDays: 30, archiveDays: 90 };
25	
26	const SIDECAR_NAME = '.telemetry.json';
27	const CONFIG_NAME = '.telemetry-config.json';
28	
29	const DAY_MS = 24 * 60 * 60 * 1000;
30	
31	// ---------- 경로 ----------
32	
33	function sidecarPath() {
34	  return path.join(paths.canonicalRoot(), SIDECAR_NAME);
35	}
36	
37	function configPath() {
38	  return path.join(paths.canonicalRoot(), CONFIG_NAME);
39	}
40	
41	// ---------- 설정/사이드카 입출력 ----------
42	
43	// 노후화 임계값을 읽는다. 인자(overrides)가 최우선, 그다음 설정 파일, 마지막이 코드 상수.
44	function loadThresholds(overrides) {
45	  let fileCfg = {};
46	  try {
47	    if (fs.existsSync(configPath())) {
48	      fileCfg = JSON.parse(fs.readFileSync(configPath(), 'utf8')) || {};
49	    }
50	  } catch {
51	    // 설정 파일이 깨졌으면 조용히 기본값으로 폴백(telemetry가 죽으면 안 된다).
52	    fileCfg = {};
53	  }
54	  return { ...DEFAULT_THRESHOLDS, ...fileCfg, ...(overrides || {}) };
55	}
56	
57	// 사이드카(.telemetry.json)를 읽는다. 없거나 깨졌으면 빈 객체.
58	function load() {
59	  try {
60	    if (!fs.existsSync(sidecarPath())) return {};
61	    return JSON.parse(fs.readFileSync(sidecarPath(), 'utf8')) || {};
62	  } catch {
63	    return {};
64	  }
65	}
66	
67	// 사이드카를 저장한다.
68	function save(data) {
69	  fs.mkdirSync(paths.canonicalRoot(), { recursive: true });
70	  fs.writeFileSync(sidecarPath(), JSON.stringify(data, null, 2) + '\n');
71	  return data;
72	}
73	
74	// ---------- canonical 항목 목록 ----------
75	
76	// canonical에 존재하는 모든 항목을 { id, file } 로 모은다.
77	//  - skill : canonical/skills/<name>/SKILL.md
78	//  - agent : canonical/agents/<id>.json
79	//  - 지시문 : canonical/instructions/<id>.md  (현재 슬라이스는 instr-global 1개)
80	// file 은 절대 경로(git 상대경로 계산과 mtime 둘 다에 쓴다).
81	function listItems() {
82	  const items = [];
83	
84	  // skill: meta.name 으로 폴더를 찾는다.
85	  for (const meta of canonical.listSkills()) {
86	    items.push({
87	      id: meta.id, // 'skill-<name>'
88	      kind: 'skill',
89	      file: path.join(canonical.skillsDir(), meta.name, 'SKILL.md'),
90	    });
91	  }
92	
93	  // agent: <id>.json
94	  for (const agent of canonical.listAgents()) {
95	    items.push({
96	      id: agent.id,
97	      kind: 'agent',
98	      file: path.join(canonical.agentsDir(), `${agent.id}.json`),
99	    });
100	  }
101	
102	  // 지시문(글로벌). 현재는 instr-global 하나만 다룬다.
103	  const INSTR_ID = 'instr-global';
104	  if (canonical.exists(INSTR_ID)) {
105	    items.push({
106	      id: INSTR_ID,
107	      kind: 'instruction',
108	      file: path.join(canonical.instrDir(), `${INSTR_ID}.md`),
109	    });
110	  }
111	
112	  return items;
113	}
114	
115	// ---------- A 신호: git 이력 또는 mtime 폴백 ----------
116	
117	// canonicalRoot 가 git 저장소인지 한 번만 확인한다.
118	function isGitRepo(root) {
119	  try {
120	    execFileSync('git', ['rev-parse', '--is-inside-work-tree'], { cwd: root, stdio: 'ignore' });
121	    return true;
122	  } catch {
123	    return false;
124	  }
125	}
126	
127	// 한 파일의 A 신호를 계산한다.
128	// 반환: { churn_count, last_changed(ISO|null), source: 'git'|'mtime' }
129	function computeChangeSignal(file, root, gitAvailable) {
130	  // 1) git 이력 우선
131	  if (gitAvailable) {
132	    try {
133	      const rel = path.relative(root, file);
134	      // 각 커밋의 committer date(ISO)를 한 줄씩. 해당 파일을 건드린 커밋만.
135	      const out = execFileSync('git', ['log', '--format=%cI', '--', rel], {
136	        cwd: root,
137	        encoding: 'utf8',
138	      });
139	      const lines = out.split('\n').map((s) => s.trim()).filter(Boolean);
140	      if (lines.length > 0) {
141	        return {
142	          churn_count: lines.length, // 이 파일을 건드린 커밋 수
143	          last_changed: lines[0], // git log 는 최신순 → 첫 줄이 최종 변경 시각
144	          source: 'git',
145	        };
146	      }
147	      // 커밋 이력이 없으면(아직 add/commit 안 됨) mtime 폴백으로 떨어진다.
148	    } catch {
149	      // git 호출 실패 시 mtime 폴백.
150	    }
151	  }
152	
153	  // 2) mtime 폴백: churn 은 알 수 없으므로 0, last_changed 는 파일 수정 시각.
154	  try {
155	    const st = fs.statSync(file);
156	    return {
157	      churn_count: 0,
158	      last_changed: new Date(st.mtimeMs).toISOString(),
159	      source: 'mtime',
160	    };
161	  } catch {
162	    // 파일이 없으면(이론상) 신호 없음.
163	    return { churn_count: 0, last_changed: null, source: 'mtime' };
164	  }
165	}
166	
167	// ---------- 상태(노후화) 계산 ----------
168	
169	// 두 ISO 시각 중 더 최근 것을 ISO 로 반환(없으면 null). 활동 시각 계산에 쓴다.
170	function latestActivity(meta) {
171	  const times = [meta.last_changed, meta.last_invoked].filter(Boolean).map((t) => Date.parse(t));
172	  const valid = times.filter((n) => !Number.isNaN(n));
173	  if (valid.length === 0) return null;
174	  return new Date(Math.max(...valid)).toISOString();
175	}
176	
177	// 결정론적 상태 전이. pinned 면 무조건 active 로 본다(자동 전이 제외).
178	// now 는 Date 또는 ISO/타임스탬프. thresholds 는 {staleDays, archiveDays}.
179	function getState(meta, now, thresholds) {
180	  const th = { ...DEFAULT_THRESHOLDS, ...(thresholds || {}) };
181	  if (meta && meta.pinned) return 'active';
182	
183	  const activity = latestActivity(meta);
184	  // 활동 시각을 전혀 모르면 보수적으로 active(섣불리 archive 하지 않는다).
185	  if (!activity) return 'active';
186	
187	  const nowMs = now instanceof Date ? now.getTime() : Date.parse(now);
188	  const idleDays = (nowMs - Date.parse(activity)) / DAY_MS;
189	
190	  if (idleDays >= th.archiveDays) return 'archived';
191	  if (idleDays >= th.staleDays) return 'stale';
192	  return 'active';
193	}
194	
195	// ---------- pin / unpin ----------
196	
197	// 항목을 pin/unpin 한다. 사이드카에 항목이 없으면 새로 만든다(기본 스키마로).
198	function setPinned(id, pinned) {
199	  const data = load();
200	  data[id] = mergeRecord(data[id], { pinned: !!pinned });
201	  save(data);
202	  return data[id];
203	}
204	
205	function pin(id) {
206	  return setPinned(id, true);
207	}
208	
209	function unpin(id) {
210	  return setPinned(id, false);
211	}
212	
213	// ---------- 레코드 병합(스키마 단일 출처) ----------
214	
215	// 기본 스키마. B(invocation_count·last_invoked)는 0/null 기본 — 별도 작업이 채운다.
216	function baseRecord() {
217	  return {
218	    churn_count: 0,
219	    last_changed: null,
220	    invocation_count: 0,
221	    last_invoked: null,
222	    signal_sources: [],
223	    state: 'active',
224	    pinned: false,
225	  };
226	}
227	
228	// 기존 레코드 위에 patch 를 덮어쓴다. B 필드(invocation_count·last_invoked)는
229	// patch 에 명시되지 않으면 항상 기존 값을 보존한다 — A 재계산이 B를 지우면 안 된다.
230	function mergeRecord(prev, patch) {
231	  const base = { ...baseRecord(), ...(prev || {}) };
232	  return { ...base, ...(patch || {}) };
233	}
234	
235	// ---------- 재계산(메인 진입점) ----------
236	
237	// 모든 canonical 항목의 A 신호를 다시 계산하고, 상태를 전이해 사이드카를 갱신·반환한다.
238	//  - now: 활동/노후화 기준 시각(테스트 용이성을 위해 인자로 받는다). 생략 시 new Date().
239	//  - thresholds: {staleDays, archiveDays} 덮어쓰기(생략 시 설정 파일/상수).
240	// B 값은 보존한다(이 함수는 A만 갱신).
241	function recompute(now, thresholds) {
242	  const nowDate = now instanceof Date ? now : now ? new Date(now) : new Date();
243	  const th = loadThresholds(thresholds);
244	
245	  const root = paths.canonicalRoot();
246	  const gitAvailable = isGitRepo(root);
247	
248	  const data = load();
249	  const items = listItems();
250	  const seen = new Set();
251	
252	  for (const item of items) {
253	    seen.add(item.id);
254	    const prev = data[item.id];
255	    const a = computeChangeSignal(item.file, root, gitAvailable);
256	
257	    // signal_sources: A 출처('git'|'mtime')를 보장하고, 기존 B 출처(예: 'claude:transcript')는 유지.
258	    const prevSources = (prev && Array.isArray(prev.signal_sources) ? prev.signal_sources : []).filter(
259	      (s) => s !== 'git' && s !== 'mtime'
260	    );
261	    const signal_sources = [a.source, ...prevSources];
262	
263	    // A 신호와 출처만 갱신(병합으로 B 보존).
264	    let rec = mergeRecord(prev, {
265	      churn_count: a.churn_count,
266	      last_changed: a.last_changed,
267	      signal_sources,
268	    });
269	
270	    // 상태 전이는 갱신된 A(+보존된 B)를 바탕으로 계산.
271	    rec.state = getState(rec, nowDate, th);
272	    data[item.id] = rec;
273	  }
274	
275	  // canonical 에서 사라진 항목은 사이드카에 남겨둔다(이력/복구 목적). 삭제하지 않는다.
276	
277	  save(data);
278	  return data;
279	}
280	
281	// ---------- 조회 ----------
282	
283	// 항목 목록 + telemetry + 상태를 합쳐 반환. 재계산은 하지 않고 현재 사이드카를 읽는다.
284	// 사이드카에 없는 항목은 기본 스키마로 채워 함께 반환한다.
285	function list(now, thresholds) {
286	  const nowDate = now instanceof Date ? now : now ? new Date(now) : new Date();
287	  const th = loadThresholds(thresholds);
288	  const data = load();
289	
290	  return listItems().map((item) => {
291	    const telemetry = mergeRecord(data[item.id], {});
292	    return {
293	      id: item.id,
294	      kind: item.kind,
295	      telemetry,
296	      state: telemetry.pinned ? 'active' : getState(telemetry, nowDate, th),
297	    };
298	  });
299	}
300	
301	module.exports = {
302	  // 입출력
303	  load,
304	  save,
305	  loadThresholds,
306	  sidecarPath,
307	  configPath,
308	  // 핵심
309	  recompute,
310	  getState,
311	  list,
312	  listItems,
313	  // pin
314	  pin,
315	  unpin,
316	  // 내부 신호(테스트/재사용용으로 노출)
317	  computeChangeSignal,
318	  latestActivity,
319	  isGitRepo,
320	  DEFAULT_THRESHOLDS,
321	};
322

1	'use strict';
2	// Phase 2 유지보수 로직: 사용량 조회(usage) + 점검 패스(review) + 제안 staging + archive.
3	// 원칙(plan2.md): 자동 적용 없음 — 전부 제안 → 승인/거절. 삭제 없음 — archive(복구 가능).
4	//
5	// telemetry(A 신호·노후화) + duplicate(중복 탐지)를 묶어 "제안"을 만들고,
6	// 승인 시에만 안전한 동작(archive 이동)을 한다. canonical 변경은 git 커밋(가능할 때).
7	
8	const fs = require('fs');
9	const path = require('path');
10	const { execFileSync } = require('child_process');
11	
12	const paths = require('./paths');
13	const canonical = require('./canonical');
14	const telemetry = require('./telemetry');
15	const duplicate = require('./duplicate');
16	const synclog = require('./synclog');
17	
18	// 테스트 용이성: now 기준 시각을 환경변수로도 주입 가능(AAD_NOW). 없으면 현재.
19	function defaultNow() {
20	  return process.env.AAD_NOW ? new Date(process.env.AAD_NOW) : new Date();
21	}
22	
23	// canonical 변경 커밋(로컬 전용). git 미초기화/변경없음이면 조용히 스킵(더미 모드 등).
24	// 주의: canonical 폴더 "자체"가 git 저장소일 때만 커밋한다. 자체 저장소가 아니면
25	// rev-parse가 상위(프로젝트) 저장소에서 성공해 add -A가 저장소 전체를 커밋해버리므로
26	// toplevel == canonicalRoot 을 확인하고, add도 canonical 하위로만 한정한다.
27	function gitCommit(message) {
28	  const cwd = paths.canonicalRoot();
29	  let top;
30	  try {
31	    top = execFileSync('git', ['rev-parse', '--show-toplevel'], { cwd, encoding: 'utf8' }).trim();
32	  } catch {
33	    return;
34	  }
35	  try {
36	    if (path.resolve(fs.realpathSync(top)) !== path.resolve(fs.realpathSync(cwd))) return;
37	  } catch {
38	    return;
39	  }
40	  try {
41	    execFileSync('git', ['add', '-A', '--', '.'], { cwd, stdio: 'ignore' });
42	    execFileSync('git', ['commit', '-m', message], { cwd, stdio: 'ignore' });
43	  } catch {
44	    /* 변경 없음 등 무시 */
45	  }
46	}
47	
48	// 모든 canonical 항목을 { id, name, text, type } 로 모은다(중복 탐지/표시용).
49	function collectItems() {
50	  const items = [];
51	  const instr = canonical.read('instr-global');
52	  if (instr) items.push({ id: 'instr-global', name: 'instr-global', text: instr.body, type: 'instruction' });
53	  for (const a of canonical.listAgents()) {
54	    items.push({ id: a.id, name: a.name, text: `${a.description || ''}\n${a.system_prompt || ''}`, type: 'agent' });
55	  }
56	  for (const meta of canonical.listSkills()) {
57	    const s = canonical.readSkill(meta.name);
58	    items.push({ id: meta.id, name: meta.name, text: s ? s.body : '', type: 'skill' });
59	  }
60	  return items;
61	}
62	
63	// ---------- 사용량 조회(A 신호 + 상태 + LRU) ----------
64	function usage(now, thresholds) {
65	  const nowDate = now || defaultNow();
66	  telemetry.recompute(nowDate, thresholds); // A 재계산(사이드카 갱신)
67	  const rows = telemetry.list(nowDate, thresholds).map((x) => ({
68	    ...x,
69	    lastActivity: telemetry.latestActivity(x.telemetry),
70	  }));
71	  // LRU: 활동이 오래된(또는 없는) 순으로 정렬
72	  rows.sort((a, b) => (a.lastActivity || '').localeCompare(b.lastActivity || ''));
73	  return { now: nowDate.toISOString(), items: rows };
74	}
75	
76	// ---------- 제안 staging 저장소 ----------
77	function proposalsPath() {
78	  return path.join(paths.canonicalRoot(), '.proposals.json');
79	}
80	function loadProposals() {
81	  try {
82	    return JSON.parse(fs.readFileSync(proposalsPath(), 'utf8')) || [];
83	  } catch {
84	    return [];
85	  }
86	}
87	function saveProposals(list) {
88	  fs.mkdirSync(paths.canonicalRoot(), { recursive: true });
89	  fs.writeFileSync(proposalsPath(), JSON.stringify(list, null, 2) + '\n');
90	}
91	
92	// ---------- 점검 패스(review) ----------
93	// 재계산 → 상태 전이 → 제안 생성. dryRun이면 리포트만, 아니면 staging + 리포트.
94	function review({ now, thresholds, dryRun = false } = {}) {
95	  const nowDate = now || defaultNow();
96	  telemetry.recompute(nowDate, thresholds);
97	  const states = telemetry.list(nowDate, thresholds);
98	  const items = collectItems();
99	
100	  const proposals = [];
101	  let seq = 0;
102	  const nextId = (k) => `prop-${k}-${++seq}`;
103	  const churnTrigger = (thresholds && thresholds.churnTrigger) || 5;
104	
105	  // 1) archived 상태 + 미pin → archive 제안(승인 시 실제 이동, 복구 가능)
106	  for (const x of states) {
107	    if (x.state === 'archived' && !x.telemetry.pinned) {
108	      proposals.push({
109	        id: nextId('archive'),
110	        kind: 'archive',
111	        target: x.id,
112	        title: `'${x.id}' 장기 미사용 → archive`,
113	        detail: '상태 archived. canonical archive 영역으로 이동(복구 가능, 삭제 아님).',
114	        status: 'pending',
115	      });
116	    }
117	  }
118	  // 2) 중복/유사 → consolidate 제안(정보형: 자동 병합하지 않고 사용자 판단)
119	  for (const pair of duplicate.findDuplicates(items, {})) {
120	    proposals.push({
121	      id: nextId('dup'),
122	      kind: 'consolidate',
123	      target: [pair.a.id, pair.b.id],
124	      title: `유사 항목: ${pair.a.name} ↔ ${pair.b.name} (score ${pair.score.toFixed(2)})`,
125	      detail: `${pair.reasons.join('; ')} — 통합할지 / 둘 다 둘지 선택.`,
126	      status: 'pending',
127	    });
128	  }
129	  // 3) churn 높음 → 새 버전/분리 제안(정보형)
130	  for (const x of states) {
131	    if ((x.telemetry.churn_count || 0) >= churnTrigger && !x.telemetry.pinned) {
132	      proposals.push({
133	        id: nextId('version'),
134	        kind: 'version',
135	        target: x.id,
136	        title: `'${x.id}' 자주 수정됨(churn ${x.telemetry.churn_count}) → 새 버전/분리?`,
137	        detail: '편집이 잦음. 새 버전으로 올리거나 reference로 분리 검토.',
138	        status: 'pending',
139	      });
140	    }
141	  }
142	
143	  const report = {
144	    ran_at: nowDate.toISOString(),
145	    counts: { items: items.length, proposals: proposals.length },
146	    states: states.reduce((acc, x) => ((acc[x.state] = (acc[x.state] || 0) + 1), acc), {}),
147	    proposals,
148	  };
149	
150	  if (!dryRun) {
151	    saveProposals(proposals); // 모든 변경은 staging(자동 적용 없음)
152	    writeReport(report, nowDate);
153	    synclog.recordReview(); // 마지막 점검 시각 기록
154	    gitCommit(`review: 제안 ${proposals.length}개 staging`);
155	  }
156	  return { dryRun, report };
157	}
158	
159	// 리포트(run.json + REPORT.md)를 canonical/reports/<timestamp>/ 에 남긴다(감사 가능).
160	function writeReport(report, nowDate) {
161	  const stamp = nowDate.toISOString().replace(/[:.]/g, '-');
162	  const dir = path.join(paths.canonicalRoot(), 'reports', stamp);
163	  fs.mkdirSync(dir, { recursive: true });
164	  fs.writeFileSync(path.join(dir, 'run.json'), JSON.stringify(report, null, 2) + '\n');
165	  const md = [
166	    '# Review 리포트',
167	    '',
168	    `- 실행: ${report.ran_at}`,
169	    `- 항목 수: ${report.counts.items}`,
170	    `- 제안 수: ${report.counts.proposals}`,
171	    '',
172	    '## 상태 분포',
173	    ...Object.entries(report.states).map(([k, v]) => `- ${k}: ${v}`),
174	    '',
175	    '## 제안',
176	    ...(report.proposals.length ? report.proposals.map((p) => `- [${p.kind}] ${p.title}`) : ['- (없음)']),
177	    '',
178	  ].join('\n');
179	  fs.writeFileSync(path.join(dir, 'REPORT.md'), md);
180	}
