187	function approve(id) {
188	  const list = loadProposals();
189	  const p = list.find((x) => x.id === id);
190	  if (!p) throw new Error('제안을 찾을 수 없습니다: ' + id);
191	  if (p.status !== 'pending') throw new Error('이미 처리된 제안입니다: ' + id);
192	
193	  // archive 제안만 실제(안전) 동작을 한다. consolidate/version은 정보형 → 승인 기록만.
194	  if (p.kind === 'archive') archiveItem(p.target);
195	
196	  p.status = 'approved';
197	  saveProposals(list);
198	  gitCommit(`approve: ${id} (${p.kind})`);
199	  return p;
200	}
201	
202	function reject(id) {
203	  const list = loadProposals();
204	  const p = list.find((x) => x.id === id);
205	  if (!p) throw new Error('제안을 찾을 수 없습니다: ' + id);
206	  p.status = 'rejected';
207	  saveProposals(list);
208	  return p;
209	}
