211	// ---------- archive / restore (삭제 아님, 복구 가능) ----------
212	function moveInto(srcRel, destBaseRel) {
213	  const root = paths.canonicalRoot();
214	  const src = path.join(root, srcRel);
215	  if (!fs.existsSync(src)) return false;
216	  const dest = path.join(root, destBaseRel, srcRel);
217	  fs.mkdirSync(path.dirname(dest), { recursive: true });
218	  fs.renameSync(src, dest);
219	  return true;
220	}
221	
222	// id 종류별로 canonical → archive/ 로 이동.
223	function archiveItem(id) {
224	  if (id.startsWith('skill-')) {
225	    const name = id.slice('skill-'.length);
226	    moveInto(path.join('skills', name), 'archive');
227	  } else if (id.startsWith('agent-')) {
228	    moveInto(path.join('agents', `${id}.json`), 'archive');
229	  } else if (id === 'instr-global') {
230	    moveInto(path.join('instructions', `${id}.md`), 'archive');
231	    moveInto(path.join('instructions', `${id}.meta.json`), 'archive');
232	  } else {
233	    throw new Error('archive 대상 종류를 알 수 없습니다: ' + id);
234	  }
235	  // telemetry 상태도 archived로 표시
236	  const data = telemetry.load();
237	  if (data[id]) {
238	    data[id].state = 'archived';
239	    telemetry.save(data);
240	  }
241	  gitCommit(`archive: ${id}`);
242	}
243	
244	// archive/ 에서 원위치로 복구.
245	function restoreItem(id) {
246	  const root = paths.canonicalRoot();
247	  const archiveBase = path.join(root, 'archive');
248	  const move = (rel) => {
249	    const src = path.join(archiveBase, rel);
250	    if (!fs.existsSync(src)) return false;
251	    const dest = path.join(root, rel);
252	    fs.mkdirSync(path.dirname(dest), { recursive: true });
253	    fs.renameSync(src, dest);
254	    return true;
255	  };
256	  let ok = false;
257	  if (id.startsWith('skill-')) ok = move(path.join('skills', id.slice('skill-'.length)));
258	  else if (id.startsWith('agent-')) ok = move(path.join('agents', `${id}.json`));
259	  else if (id === 'instr-global') {
260	    ok = move(path.join('instructions', `${id}.md`));
261	    move(path.join('instructions', `${id}.meta.json`));
262	  }
263	  if (!ok) throw new Error('복구할 archive 항목이 없습니다: ' + id);
264	  gitCommit(`restore: ${id}`);
265	  return { restored: id };
266	}
267	
268	module.exports = {
269	  usage,
270	  review,
271	  pending,
272	  approve,
273	  reject,
274	  archiveItem,
275	  restoreItem,
276	  loadProposals,
277	};
