160	function formatDateHuman(value) {
161	  if (!value) return '–';
162	  const d = new Date(value);
163	  if (Number.isNaN(d.getTime())) return String(value);
164	  const diff = Date.now() - d.getTime();
165	  const abs = Math.abs(diff);
166	  const mins = Math.round(abs / 60000);
167	  const hrs = Math.round(abs / 3600000);
168	  const days = Math.round(abs / 86400000);
169	  const suffix = diff >= 0 ? '전' : '후';
170	  if (mins < 1) return '방금';
171	  if (mins < 60) return `${mins}분 ${suffix}`;
172	  if (hrs < 24) return `${hrs}시간 ${suffix}`;
173	  if (days < 7) return `${days}일 ${suffix}`;
174	  return d.toLocaleDateString('ko-KR', { month: 'short', day: 'numeric' });
175	}
